    std::map<char, int> freq;
    for (char c : s) {
        freq[c]++;
    }

    // 2. Identify all unique characters and process them
    std::set<char> unique_chars;
    for (char c : s) {
        unique_chars.insert(c);
    }

    long long total_diff = 0;
    std::set<char> processed_pairs;

    for (char c : unique_chars) {
        if (processed_pairs.count(c)) {
            continue;
